import ts from"typescript";import{getPropertyValues}from"../../typescript/ast-helpers.js";export const getPageExtensions=t=>{const e=new Set;return function t(r){if(ts.isObjectLiteralExpression(r)){const t=getPropertyValues(r,"pageExtensions");for(const r of t)e.add(r)}ts.forEachChild(r,t)}(t),Array.from(e)};